/* Grid Expand — image morphs from grid item to detail page hero */

/* Prevent scrollbar from causing layout shift during transition */
html.grid-expand {
  scrollbar-gutter: stable;
}

::view-transition-group(grid-item) {
  animation-duration: 0.5s;
  animation-timing-function: cubic-bezier(0.32, 0.72, 0, 1);
  overflow: clip;
}

::view-transition-old(grid-item),
::view-transition-new(grid-item) {
  animation: none;
  mix-blend-mode: normal;
  width: 100%;
  height: 100%;
  object-fit: cover;
}

html.grid-expand::view-transition-old(root) {
  animation: grid-expand-root-out 0.35s cubic-bezier(0.32, 0.72, 0, 1) forwards;
}

html.grid-expand::view-transition-new(root) {
  animation: grid-expand-root-in 0.35s cubic-bezier(0.32, 0.72, 0, 1) 0.1s both;
}

@keyframes grid-expand-root-out {
  from { opacity: 1; }
  to   { opacity: 0; }
}

@keyframes grid-expand-root-in {
  from { opacity: 0; }
  to   { opacity: 1; }
}

/* Accessibility — respect reduced motion preference */
@media (prefers-reduced-motion: reduce) {
  ::view-transition-group(grid-item) {
    animation-duration: 0.01ms;
  }

  html.grid-expand::view-transition-old(root),
  html.grid-expand::view-transition-new(root) {
    animation-duration: 0.01ms;
  }
}

"use client"

import Link from "next/link"
import { useRouter } from "next/navigation"
import { MouseEvent, ReactNode, useRef } from "react"
import "./transition.css"

const DEFAULT_TRANSITION_NAME = "grid-item"

interface GridExpandLinkProps {
  href: string
  children: ReactNode
  className?: string
  transitionName?: string
}

function waitForTarget(name: string, timeout = 3000): Promise<void> {
  return new Promise((resolve) => {
    if (document.querySelector(`[data-grid-expand-target="${name}"]`)) {
      resolve()
      return
    }

    const observer = new MutationObserver(() => {
      if (document.querySelector(`[data-grid-expand-target="${name}"]`)) {
        observer.disconnect()
        resolve()
      }
    })

    observer.observe(document.documentElement, {
      childList: true,
      subtree: true,
    })

    setTimeout(() => {
      observer.disconnect()
      resolve()
    }, timeout)
  })
}

export function GridExpandLink({
  href,
  children,
  className,
  transitionName = DEFAULT_TRANSITION_NAME,
}: GridExpandLinkProps) {
  const router = useRouter()
  const ref = useRef<HTMLAnchorElement>(null)

  const handleClick = (e: MouseEvent<HTMLAnchorElement>) => {
    if (e.button !== 0 || e.ctrlKey || e.metaKey || e.shiftKey || e.altKey) {
      return
    }

    const isExternal =
      href.toString().startsWith("http") || href.toString().startsWith("//")
    if (isExternal) return

    e.preventDefault()

    if (!(document as any).startViewTransition) {
      router.push(href)
      return
    }

    const el = ref.current
    const source =
      el?.querySelector<HTMLElement>("[data-grid-expand]") || el
    if (source) {
      source.style.viewTransitionName = transitionName
    }

    document.documentElement.classList.add("grid-expand")

    const transition = (document as any).startViewTransition(async () => {
      if (source) {
        source.style.viewTransitionName = ""
      }
      router.push(href)
      await waitForTarget(transitionName)
    })

    transition.finished.finally(() => {
      if (source) {
        source.style.viewTransitionName = ""
      }
      document.documentElement.classList.remove("grid-expand")
    })
  }

  const prefetch = () => router.prefetch(href)

  return (
    <Link
      ref={ref}
      href={href}
      onClick={handleClick}
      onMouseEnter={prefetch}
      onTouchStart={prefetch}
      className={className}
    >
      {children}
    </Link>
  )
}

import { ReactNode } from "react"

const DEFAULT_TRANSITION_NAME = "grid-item"

interface GridExpandTargetProps {
  children: ReactNode
  className?: string
  transitionName?: string
}

export function GridExpandTarget({
  children,
  className,
  transitionName = DEFAULT_TRANSITION_NAME,
}: GridExpandTargetProps) {
  return (
    <div
      data-grid-expand-target={transitionName}
      className={className}
      style={{ viewTransitionName: transitionName, contain: "layout paint" }}
    >
      {children}
    </div>
  )
}

