// Grid page (app/products/page.tsx)
import { GridExpandLink } from "@/transitions/grid-expand"

const products = [
  { id: 1, name: "Lunar Sneakers", price: 120, image: "https://picsum.photos/seed/sneakers/400/300" },
  { id: 2, name: "Orbit Hoodie",   price: 85,  image: "https://picsum.photos/seed/hoodie/400/300" },
  { id: 3, name: "Nova Backpack",  price: 95,  image: "https://picsum.photos/seed/backpack/400/300" },
  { id: 4, name: "Cosmo Watch",    price: 250, image: "https://picsum.photos/seed/watch/400/300" },
]

export default function ProductsPage() {
  return (
    <div className="grid grid-cols-2 gap-4 p-6">
      {products.map((p) => (
        <GridExpandLink key={p.id} href={`/products/${p.id}`}>
          {/* Mark the element to morph with data-grid-expand */}
          <img data-grid-expand src={p.image} alt={p.name} />
          <h3>{p.name}</h3>
          <span>${p.price}</span>
        </GridExpandLink>
      ))}
    </div>
  )
}

// Detail page (app/products/[id]/page.tsx)
import { GridExpandTarget } from "@/transitions/grid-expand"

export default async function ProductPage({
  params,
}: {
  params: Promise<{ id: string }>
}) {
  const { id } = await params
  // Replace with your own data fetching
  const product = { id, name: "Lunar Sneakers", image: "https://picsum.photos/seed/sneakers/400/300" }

  return (
    <div>
      <GridExpandTarget>
        <img src={product.image} alt={product.name} />
      </GridExpandTarget>
      <h1>{product.name}</h1>
    </div>
  )
}

